mapper.insert:

    SELECT TRAVEL_ITINERARY_SEQ.NEXTVAL FROM DUAL

INSERT INTO TRAVEL_ITINERARY
    (TRAVEL_ITINERARY_NO, TRAVEL_PLAN_NO, ITINERARY_DT, ITINERARY_NM
    , ITINERARY_TIME
    , ITINERARY_MEMO
    , CONTENT_NO
    )
VALUES
    (#{id}, #{planNo}, TO_DATE(#{itineraryDt}, 'YYYY-MM-DD'), #{title}
    , #{time}
    , #{content}
    , #{contentNo}
    )

mapper.update:
UPDATE TRAVEL_ITINERARY
ITINERARY_DT = TO_DATE(#{itineraryDt}, 'YYYY-MM-DD'), ITINERARY_NM = #{title}, ITINERARY_TIME = #{time}NULL, ITINERARY_MEMO = #{content}NULL, CONTENT_NO = #{contentNo}NULL
WHERE TRAVEL_ITINERARY_NO = #{id} AND TRAVEL_PLAN_NO = #{planNo}

mapper.delete:
DELETE FROM TRAVEL_ITINERARY
 WHERE TRAVEL_ITINERARY_NO = #{no}
   AND TRAVEL_PLAN_NO      = #{planNo}

mapper.select:
SELECT TO_CHAR(TRAVEL_START_DT, 'YYYY-MM-DD')
  FROM TRAVEL_PLAN
 WHERE TRAVEL_PLAN_NO = #{planNo}

SELECT PG.PLAN_GUEST_NO
  FROM PLAN_GUEST PG
 WHERE PG.TRAVEL_PLAN_NO = #{planNo}
   AND PG.MEMBER_NO      = #{memberNo}
   AND NOT EXISTS (
       SELECT 1 FROM PLAN_GUEST_LEAVE PGL
        WHERE PGL.PLAN_GUEST_NO = PG.PLAN_GUEST_NO
   )

SELECT NVL(PG.CAN_EDIT, 1)
  FROM PLAN_GUEST PG
 WHERE PG.TRAVEL_PLAN_NO = #{planNo}
   AND PG.MEMBER_NO      = #{memberNo}
   AND NOT EXISTS (
       SELECT 1 FROM PLAN_GUEST_LEAVE PGL
        WHERE PGL.PLAN_GUEST_NO = PG.PLAN_GUEST_NO
   )
